-- Sprint 6.1.3: professional exercise coverage expansion by muscle group.
-- Safe migration: no deletes, no existing id changes, no media without license.
-- This supersedes the unapplied Sprint 6.1.2 migration. If 6.1.2 was not applied,
-- apply this migration after Sprint 6 and Sprint 6.1.

ALTER TABLE public.exercises
  ADD COLUMN IF NOT EXISTS instrucciones text[] NOT NULL DEFAULT '{}'::text[];

ALTER TABLE public.exercises
  ADD COLUMN IF NOT EXISTS aliases text[] NOT NULL DEFAULT '{}'::text[];

ALTER TABLE public.exercises
  DROP CONSTRAINT IF EXISTS exercises_estado_calidad_check;

ALTER TABLE public.exercises
  ADD CONSTRAINT exercises_estado_calidad_check
  CHECK (estado_calidad IN ('legacy', 'pendiente', 'basico', 'revisar', 'curado', 'deprecado', 'premium'));

CREATE TEMP TABLE sprint613_exercise_catalog (
  id text PRIMARY KEY,
  existed_before boolean NOT NULL DEFAULT false,
