  equipamiento text NOT NULL,
  equipo_requerido text[] NOT NULL,
  lugar text NOT NULL,
  objetivo text NOT NULL,
  tipo_entrenamiento text NOT NULL,
  patron_movimiento text NOT NULL,
  descripcion text NOT NULL,
  instrucciones text[] NOT NULL,
  cues_tecnicos text[] NOT NULL,
  errores_comunes text[] NOT NULL,
  contraindicaciones text[] NOT NULL,
  sustituciones text[] NOT NULL,
  progresiones text[] NOT NULL,
  regresiones text[] NOT NULL,
  series_sugeridas integer,
  repeticiones_sugeridas integer,
  rango_reps_min integer,
  rango_reps_max integer,
  descanso_segundos_min integer,
  descanso_segundos_max integer,
  rir_recomendado integer,
  duracion_promedio_segundos integer,
  estado_calidad text NOT NULL DEFAULT 'curado',
  not_added_reason text
) ON COMMIT DROP;

