-- Update existing rows from the catalog.
UPDATE public.exercises e
SET
  nombre = c.nombre,
  aliases = c.aliases,
  nivel = c.nivel,
  nivel_minimo = c.nivel_minimo,
  grupo_muscular = c.grupo_muscular,
  musculo_principal = c.musculo_principal,
  musculos_secundarios = c.musculos_secundarios,
  equipamiento = c.equipamiento,
  equipo_requerido = c.equipo_requerido,
  lugar = c.lugar,
  objetivo = c.objetivo,
  tipo_entrenamiento = c.tipo_entrenamiento,
  patron_movimiento = c.patron_movimiento,
  descripcion = c.descripcion,
  instrucciones = c.instrucciones,
  cues_tecnicos = c.cues_tecnicos,
  errores_comunes = c.errores_comunes,
  contraindicaciones = c.contraindicaciones,
  sustituciones = c.sustituciones,
  progresiones = c.progresiones,
  regresiones = c.regresiones,
  series_sugeridas = c.series_sugeridas,
  repeticiones_sugeridas = c.repeticiones_sugeridas,
  rango_reps_min = c.rango_reps_min,
  rango_reps_max = c.rango_reps_max,
  descanso_segundos_min = c.descanso_segundos_min,
  descanso_segundos_max = c.descanso_segundos_max,
  rir_recomendado = c.rir_recomendado,
  duracion_promedio_segundos = c.duracion_promedio_segundos,
  estado_calidad = c.estado_calidad
FROM sprint613_exercise_catalog c
WHERE e.id = c.id
  AND c.existed_before = true;

-- Insert new professional variants.
INSERT INTO public.exercises (
  id, nombre, aliases, nivel, nivel_minimo, grupo_muscular, musculo_principal,
  musculos_secundarios, equipamiento, equipo_requerido, lugar, objetivo,
  tipo_entrenamiento, patron_movimiento, descripcion, instrucciones, cues_tecnicos,
  errores_comunes, contraindicaciones, sustituciones, progresiones, regresiones,
  series_sugeridas, repeticiones_sugeridas, rango_reps_min, rango_reps_max,
  descanso_segundos_min, descanso_segundos_max, rir_recomendado,
  duracion_promedio_segundos, estado_calidad, imagen, video
)
SELECT
  id, nombre, aliases, nivel, nivel_minimo, grupo_muscular, musculo_principal,
  musculos_secundarios, equipamiento, equipo_requerido, lugar, objetivo,
  tipo_entrenamiento, patron_movimiento, descripcion, instrucciones, cues_tecnicos,
  errores_comunes, contraindicaciones, sustituciones, progresiones, regresiones,
  series_sugeridas, repeticiones_sugeridas, rango_reps_min, rango_reps_max,
  descanso_segundos_min, descanso_segundos_max, rir_recomendado,
  duracion_promedio_segundos, estado_calidad, NULL, NULL
FROM sprint613_exercise_catalog
WHERE existed_before = false
ON CONFLICT (id) DO UPDATE SET
  nombre = EXCLUDED.nombre,
  aliases = EXCLUDED.aliases,
  nivel = EXCLUDED.nivel,
  nivel_minimo = EXCLUDED.nivel_minimo,
  grupo_muscular = EXCLUDED.grupo_muscular,
  musculo_principal = EXCLUDED.musculo_principal,
  musculos_secundarios = EXCLUDED.musculos_secundarios,
  equipamiento = EXCLUDED.equipamiento,
  equipo_requerido = EXCLUDED.equipo_requerido,
