  repeticiones_sugeridas = EXCLUDED.repeticiones_sugeridas,
  rango_reps_min = EXCLUDED.rango_reps_min,
  rango_reps_max = EXCLUDED.rango_reps_max,
  descanso_segundos_min = EXCLUDED.descanso_segundos_min,
