  estado_calidad = EXCLUDED.estado_calidad;

-- Remove accidental self-substitutions and duplicates while preserving order.
UPDATE public.exercises e
SET sustituciones = cleaned.items
FROM (
  SELECT
    id,
    COALESCE(array_agg(item ORDER BY first_seen) FILTER (WHERE item IS NOT NULL), '{}'::text[]) AS items
  FROM (
    SELECT
      e.id,
      s.item,
      min(s.ordinality) AS first_seen
    FROM public.exercises e
    LEFT JOIN LATERAL unnest(e.sustituciones) WITH ORDINALITY AS s(item, ordinality) ON true
    WHERE s.item IS NULL
       OR (
        lower(trim(s.item)) <> lower(trim(e.nombre))
        AND lower(trim(s.item)) <> ALL (
          SELECT lower(trim(alias_item))
          FROM unnest(e.aliases) AS alias_item
        )
      )
    GROUP BY e.id, s.item
  ) deduped
  GROUP BY id
) cleaned
WHERE e.id = cleaned.id;

-- Cardio uses duration instead of strength reps/RIR.
UPDATE public.exercises
SET rango_reps_min = NULL,
    rango_reps_max = NULL,
    rir_recomendado = NULL
WHERE tipo_entrenamiento ILIKE 'cardio%';

COMMENT ON COLUMN public.exercises.instrucciones IS
  'Step-by-step exercise execution instructions. Added for Sprint 6.1.3 professional exercise library.';

